//! Perception inner-math kernels — the "sicknasty fast math" of the hot path.
//!
//! These are the per-pixel / per-element primitives the perception pipeline runs on EVERY frame:
//! luma reduction, the EMA background update, the foreground difference, the 16x16 / 8x8 content
//! signatures, and the signature L1 motion energy. Each kernel ships TWICE:
//!
//!   - a portable **scalar** implementation (the native path, and the wasm fallback if `simd128`
//!     is not enabled), and
//!   - a **wasm SIMD** implementation built on `core::arch::wasm32` (`v128` / `f32x4` / `u8x16`),
//!     compiled only under `cfg(all(target_arch = "wasm32", target_feature = "simd128"))`.
//!
//! This mirrors the sovereign in-repo pattern (`wasm-modules/transformer-inference/src/lib.rs`
//! `#[cfg(target_arch = "wasm32")] use core::arch::wasm32::*;`, built with a crate-level
//! `.cargo/config.toml` `rustflags = ["-C", "target-feature=+simd128"]`) and the aether C kernels'
//! `<wasm_simd128.h>` `wasm_f32x4_*` style — but kept in-crate in Rust so the perception math stays
//! sovereign and has zero external link surface (aether's kernels are quantized-matvec/rmsnorm for
//! ML inference, the wrong shape for perception, and are a C/TS module, not a linkable Rust crate).
//!
//! ## Parity is load-bearing
//!
//! The SIMD lanes perform the SAME arithmetic, in the SAME element order, as the scalar loop, so the
//! two paths are **bit-identical**: integer luma keeps integer ops `(r*54 + g*183 + b*19) >> 8`; the
//! f32 EMA and the f32 foreground diff process 4 contiguous lanes exactly as the scalar loop does one
//! at a time. That identity is what lets native (scalar) and wasm (SIMD) ticks MATCH byte-for-byte.
//! `tests` below assert scalar == simd on the same inputs (the simd assertions run when the target
//! has `simd128`).

/// Rec.601-ish integer luma of one packed-RGB pixel: `(r*54 + g*183 + b*19) >> 8`, the exact weights
/// every other module uses. Kept as a `#[inline]` so the scalar reducers below match it verbatim.
#[inline(always)]
pub fn luma_u8(r: u8, g: u8, b: u8) -> u32 {
    ((r as u32) * 54 + (g as u32) * 183 + (b as u32) * 19) >> 8
}

// ───────────────────────────── EMA background update ─────────────────────────────
//
// `mean[i] += alpha * (luma[i] - mean[i])` over the whole work-resolution buffer (vision.rs hot
// loop). f32x4 over 4 contiguous lanes == the scalar loop's 4 successive iterations, bit-identical.

/// Scalar EMA: the reference. `mean` and `luma` are equal length.
#[inline]
pub fn ema_update_scalar(mean: &mut [f32], luma: &[f32], alpha: f32) {
    debug_assert_eq!(mean.len(), luma.len());
    for i in 0..mean.len() {
        mean[i] += alpha * (luma[i] - mean[i]);
    }
}

#[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
#[inline]
fn ema_update_simd(mean: &mut [f32], luma: &[f32], alpha: f32) {
    use core::arch::wasm32::*;
    debug_assert_eq!(mean.len(), luma.len());
    let n = mean.len();
    let n4 = n & !3;
    let a = f32x4_splat(alpha);
    let mp = mean.as_mut_ptr();
    let lp = luma.as_ptr();
    let mut i = 0;
    while i < n4 {
        // SAFETY: i + 4 <= n4 <= n, both buffers are length n, 16-byte loads/stores in range.
        unsafe {
            let m = v128_load(mp.add(i) as *const v128);
            let l = v128_load(lp.add(i) as *const v128);
            // m + a*(l - m), same op order as the scalar loop's `mean += alpha*(luma-mean)`.
            let upd = f32x4_add(m, f32x4_mul(a, f32x4_sub(l, m)));
            v128_store(mp.add(i) as *mut v128, upd);
        }
        i += 4;
    }
    for j in n4..n {
        mean[j] += alpha * (luma[j] - mean[j]);
    }
}

/// EMA background update — SIMD on wasm+simd128, scalar elsewhere. Bit-identical across paths.
#[inline]
pub fn ema_update(mean: &mut [f32], luma: &[f32], alpha: f32) {
    #[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
    {
        ema_update_simd(mean, luma, alpha);
    }
    #[cfg(not(all(target_arch = "wasm32", target_feature = "simd128")))]
    {
        ema_update_scalar(mean, luma, alpha);
    }
}

// ───────────────────────────── Foreground difference ─────────────────────────────
//
// `fg[i] = (|luma[i] - bg[i]| > thresh) as u8`, returning the set-pixel count. The plain
// static-camera path (vision.rs `else` branch). f32x4 abs via clearing the sign bit; compare via
// `f32x4_gt`; the bitmask popcount yields the per-4 count — same predicate as the scalar `>`.

/// Scalar foreground diff: the reference. Writes `fg` (0/1) and returns the foreground count.
#[inline]
pub fn foreground_diff_scalar(luma: &[f32], bg: &[f32], thresh: f32, fg: &mut [u8]) -> usize {
    debug_assert_eq!(luma.len(), bg.len());
    debug_assert_eq!(luma.len(), fg.len());
    let mut count = 0usize;
    for i in 0..luma.len() {
        if (luma[i] - bg[i]).abs() > thresh {
            fg[i] = 1;
            count += 1;
        } else {
            fg[i] = 0;
        }
    }
    count
}

#[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
#[inline]
fn foreground_diff_simd(luma: &[f32], bg: &[f32], thresh: f32, fg: &mut [u8]) -> usize {
    use core::arch::wasm32::*;
    let n = luma.len();
    let n4 = n & !3;
    let absmask = i32x4_splat(0x7fff_ffff); // clear the sign bit -> abs for f32
    let th = f32x4_splat(thresh);
    let lp = luma.as_ptr();
    let bp = bg.as_ptr();
    let mut count = 0usize;
    let mut i = 0;
    while i < n4 {
        // SAFETY: i + 4 <= n4 <= n; luma/bg are length n; fg is length n.
        unsafe {
            let l = v128_load(lp.add(i) as *const v128);
            let b = v128_load(bp.add(i) as *const v128);
            let d = v128_and(f32x4_sub(l, b), absmask); // |l - b|
            let gt = f32x4_gt(d, th); // lane = all-ones where |d| > thresh
            // Materialise 0/1 per lane and store as bytes (parity with the scalar 0/1 write). The
            // comparison result lanes are all-ones / all-zeros bit patterns; read them as i32.
            let m0 = i32x4_extract_lane::<0>(gt);
            let m1 = i32x4_extract_lane::<1>(gt);
            let m2 = i32x4_extract_lane::<2>(gt);
            let m3 = i32x4_extract_lane::<3>(gt);
            let b0 = (m0 != 0) as u8;
            let b1 = (m1 != 0) as u8;
            let b2 = (m2 != 0) as u8;
            let b3 = (m3 != 0) as u8;
            *fg.get_unchecked_mut(i) = b0;
            *fg.get_unchecked_mut(i + 1) = b1;
            *fg.get_unchecked_mut(i + 2) = b2;
            *fg.get_unchecked_mut(i + 3) = b3;
            count += (b0 + b1 + b2 + b3) as usize;
        }
        i += 4;
    }
    for j in n4..n {
        if (luma[j] - bg[j]).abs() > thresh {
            fg[j] = 1;
            count += 1;
        } else {
            fg[j] = 0;
        }
    }
    count
}

/// Foreground difference — SIMD on wasm+simd128, scalar elsewhere. Bit-identical across paths.
#[inline]
pub fn foreground_diff(luma: &[f32], bg: &[f32], thresh: f32, fg: &mut [u8]) -> usize {
    #[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
    {
        foreground_diff_simd(luma, bg, thresh, fg)
    }
    #[cfg(not(all(target_arch = "wasm32", target_feature = "simd128")))]
    {
        foreground_diff_scalar(luma, bg, thresh, fg)
    }
}

// ───────────────────────────── Signature L1 motion energy ─────────────────────────────
//
// Normalised L1 distance of two 256-byte luma signatures, in [0,1] (cadence/pipeline motion). u8x16
// absolute-difference summed across 16 chunks == the scalar `|a-b|` sum, bit-identical (both are the
// exact integer sum of per-byte |differences|).

/// Scalar L1 of two equal-length byte signatures (sum of `|a[i]-b[i]|`).
#[inline]
pub fn sig_l1_sum_scalar(a: &[u8], b: &[u8]) -> u32 {
    debug_assert_eq!(a.len(), b.len());
    let mut acc: u32 = 0;
    for i in 0..a.len() {
        acc += (a[i] as i32 - b[i] as i32).unsigned_abs();
    }
    acc
}

#[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
#[inline]
fn sig_l1_sum_simd(a: &[u8], b: &[u8]) -> u32 {
    use core::arch::wasm32::*;
    let n = a.len();
    let n16 = n & !15;
    let ap = a.as_ptr();
    let bp = b.as_ptr();
    let mut acc: u32 = 0;
    let mut i = 0;
    while i < n16 {
        // SAFETY: i + 16 <= n16 <= n; both buffers are length n; 16-byte loads in range.
        unsafe {
            let va = v128_load(ap.add(i) as *const v128);
            let vb = v128_load(bp.add(i) as *const v128);
            // |a-b| per byte = max(a,b) - min(a,b) on unsigned lanes (no signed overflow).
            let mx = u8x16_max(va, vb);
            let mn = u8x16_min(va, vb);
            let diff = u8x16_sub(mx, mn);
            // Horizontal sum of the 16 unsigned bytes: widen to u16 (low+high) then sum lanes.
            let lo = u16x8_extend_low_u8x16(diff);
            let hi = u16x8_extend_high_u8x16(diff);
            let s = u16x8_add(lo, hi);
            acc += u16x8_extract_lane::<0>(s) as u32
                + u16x8_extract_lane::<1>(s) as u32
                + u16x8_extract_lane::<2>(s) as u32
                + u16x8_extract_lane::<3>(s) as u32
                + u16x8_extract_lane::<4>(s) as u32
                + u16x8_extract_lane::<5>(s) as u32
                + u16x8_extract_lane::<6>(s) as u32
                + u16x8_extract_lane::<7>(s) as u32;
        }
        i += 16;
    }
    for j in n16..n {
        acc += (a[j] as i32 - b[j] as i32).unsigned_abs();
    }
    acc
}

/// Sum of `|a[i]-b[i]|` — SIMD on wasm+simd128, scalar elsewhere. Bit-identical across paths.
#[inline]
pub fn sig_l1_sum(a: &[u8], b: &[u8]) -> u32 {
    #[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
    {
        sig_l1_sum_simd(a, b)
    }
    #[cfg(not(all(target_arch = "wasm32", target_feature = "simd128")))]
    {
        sig_l1_sum_scalar(a, b)
    }
}

/// Normalised signature L1 distance in [0,1] for a 256-byte signature pair (the motion primitive).
#[inline]
pub fn sig_motion_256(a: &[u8; 256], b: &[u8; 256]) -> f32 {
    sig_l1_sum(a, b) as f32 / (256.0 * 255.0)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn lcg(seed: &mut u32) -> u32 {
        *seed = seed.wrapping_mul(1664525).wrapping_add(1013904223);
        *seed
    }

    #[test]
    fn ema_scalar_matches_manual() {
        let mut mean = vec![10.0f32, 20.0, 30.0, 40.0, 50.0];
        let luma = vec![14.0f32, 16.0, 30.0, 60.0, 0.0];
        let alpha = 0.25;
        let mut expect = mean.clone();
        for i in 0..expect.len() {
            expect[i] += alpha * (luma[i] - expect[i]);
        }
        ema_update_scalar(&mut mean, &luma, alpha);
        assert_eq!(mean, expect);
    }

    #[test]
    fn foreground_scalar_predicate() {
        let luma = vec![100.0f32, 100.0, 100.0, 200.0];
        let bg = vec![100.0f32, 90.0, 70.0, 100.0];
        let mut fg = vec![9u8; 4];
        let c = foreground_diff_scalar(&luma, &bg, 22.0, &mut fg);
        assert_eq!(fg, vec![0u8, 0, 1, 1]); // diffs 0,10,30,100 vs thresh 22
        assert_eq!(c, 2);
    }

    #[test]
    fn sig_l1_scalar_matches_naive() {
        let mut s = 12345u32;
        let a: Vec<u8> = (0..256).map(|_| (lcg(&mut s) & 0xff) as u8).collect();
        let b: Vec<u8> = (0..256).map(|_| (lcg(&mut s) & 0xff) as u8).collect();
        let mut naive = 0u32;
        for i in 0..256 {
            naive += (a[i] as i32 - b[i] as i32).unsigned_abs();
        }
        assert_eq!(sig_l1_sum_scalar(&a, &b), naive);
    }

    // The SIMD kernels must be BIT-IDENTICAL to the scalar reference. These run only when the target
    // actually has simd128 (the wasm build); on native they are a no-op (the simd fns aren't compiled).
    #[cfg(all(target_arch = "wasm32", target_feature = "simd128"))]
    #[test]
    fn simd_parity_ema_fg_l1() {
        let mut s = 9001u32;
        let n = 4093; // deliberately not a multiple of 4/16 -> exercises the scalar tail
        let luma: Vec<f32> = (0..n).map(|_| (lcg(&mut s) % 256) as f32).collect();
        let bg0: Vec<f32> = (0..n).map(|_| (lcg(&mut s) % 256) as f32).collect();

        let mut m_scalar = bg0.clone();
        let mut m_simd = bg0.clone();
        ema_update_scalar(&mut m_scalar, &luma, 0.04);
        ema_update_simd(&mut m_simd, &luma, 0.04);
        assert_eq!(m_scalar, m_simd, "EMA simd != scalar");

        let mut fg_s = vec![0u8; n];
        let mut fg_v = vec![0u8; n];
        let cs = foreground_diff_scalar(&luma, &bg0, 22.0, &mut fg_s);
        let cv = foreground_diff_simd(&luma, &bg0, 22.0, &mut fg_v);
        assert_eq!(cs, cv, "fg count simd != scalar");
        assert_eq!(fg_s, fg_v, "fg mask simd != scalar");

        let a: Vec<u8> = (0..256).map(|_| (lcg(&mut s) & 0xff) as u8).collect();
        let b: Vec<u8> = (0..256).map(|_| (lcg(&mut s) & 0xff) as u8).collect();
        assert_eq!(sig_l1_sum_scalar(&a, &b), sig_l1_sum_simd(&a, &b), "L1 simd != scalar");
    }
}
